    /// <summary>
    /// Generates the full registration extension method with <c>AddDecoratR()</c>.
    /// </summary>
    internal static string GenerateFullRegistrations(
        string assemblyName,
        IReadOnlyList<HandlerMetadata> localHandlers,
        IReadOnlyList<RegistrationMethodMetadata> referencedMethods,
        IReadOnlyList<HandlerMetadata> referencedServiceTypes,
        IReadOnlyList<DecoratorMetadata> decorators)
    {
        var sb = new StringBuilder();
        var totalHandlerCount = localHandlers.Count + referencedServiceTypes.Count;

        sb.AppendLine("// <auto-generated />");
        sb.AppendLine("#nullable enable");
        sb.AppendLine();
        sb.AppendLine($"namespace {assemblyName};");
        sb.AppendLine();

        // ── AddDecoratR() extension method ────────────────────────────────────
        sb.AppendLine("[global::System.CodeDom.Compiler.GeneratedCode(\"DecoratR.Generator\", \"1.0.0\")]");
        sb.AppendLine("public static class DecoratRServiceCollectionExtensions");
        sb.AppendLine("{");

        // XML summary
        sb.AppendIndentedLine(1, "/// <summary>");
        sb.AppendIndentedLine(1, "/// Registers all DecoratR handlers and decorators.");
        sb.AppendIndentedLine(1, "/// </summary>");

        sb.AppendIndentedLine(1, "public static global::Microsoft.Extensions.DependencyInjection.IServiceCollection AddDecoratR(");
        sb.AppendIndentedLine(2, "this global::Microsoft.Extensions.DependencyInjection.IServiceCollection services)");
        sb.AppendIndentedLine(1, "{");

        // Call referenced assembly registration methods
        if (referencedMethods.Count > 0)
        {
            sb.AppendIndentedLine(2, "// Register handlers from referenced assemblies");
            foreach (var method in referencedMethods)
            {
                sb.AppendIndentedLine(2, $"global::{method.FullyQualifiedClassName}.{method.MethodName}(services);");
            }
        }

        // Register local handlers
        if (localHandlers.Count > 0)
        {
            if (referencedMethods.Count > 0)
                sb.AppendLine();

            sb.AppendIndentedLine(2, "// Register local handlers");
            foreach (var handler in localHandlers)
            {
                sb.AppendIndentedLine(2, $"services.Add(new global::Microsoft.Extensions.DependencyInjection.ServiceDescriptor(");
                sb.AppendIndentedLine(3, $"typeof(global::DecoratR.IRequestHandler<{handler.RequestFullyQualifiedName}, {handler.ResponseFullyQualifiedName}>),");
                sb.AppendIndentedLine(3, $"typeof({handler.HandlerFullyQualifiedName}),");
                sb.AppendIndentedLine(3, "global::Microsoft.Extensions.DependencyInjection.ServiceLifetime.Transient));");
            }
        }

        // Apply decorators
        // Combine local + referenced service types for decorator application
        var allServiceTypes = localHandlers
            .Select(h => (h.RequestFullyQualifiedName, h.ResponseFullyQualifiedName))
            .Concat(referencedServiceTypes.Select(h => (h.RequestFullyQualifiedName, h.ResponseFullyQualifiedName)))
            .Distinct()
            .OrderBy(t => t.RequestFullyQualifiedName)
            .ThenBy(t => t.ResponseFullyQualifiedName)
            .ToList();

        if (decorators.Count > 0 && allServiceTypes.Count > 0)
        {
            sb.AppendLine();
            sb.AppendIndentedLine(2, "// Apply decorators (ordered by Order, lowest = outermost)");

