                    sb.AppendIndentedLine(2, $"global::DecoratR.ServiceCollectionExtensions.Decorate<");
                    sb.AppendIndentedLine(3, $"global::DecoratR.IRequestHandler<{requestType}, {responseType}>,");
                    sb.AppendIndentedLine(3, $"{decorator.DecoratorFullyQualifiedName}<{requestType}, {responseType}>,");
                    sb.AppendIndentedLine(3, $"{requestType},");
                    sb.AppendIndentedLine(3, $"{responseType}>(services);");
                }
            }
        }

        sb.AppendLine();
        sb.AppendIndentedLine(2, "return services;");
        sb.AppendIndentedLine(1, "}");
        sb.AppendLine("}");

        return sb.ToString();
    }

    private static string StripGlobalPrefix(string typeName) =>
        typeName.StartsWith("global::") ? typeName.Substring("global::".Length) : typeName;

    private static string SanitizeAssemblyName(string assemblyName)
    {
        var sb = new StringBuilder(assemblyName.Length);
        foreach (var c in assemblyName)
        {
            sb.Append(char.IsLetterOrDigit(c) ? c : '_');
        }
        return sb.ToString();
    }
